+            .unwrap();
+        conn.execute("INSERT INTO rhs VALUES (1, 'r1');").unwrap();
+
+        let rows = conn
+            .query(
+                "SELECT *, ROW_NUMBER() OVER (ORDER BY s.id)
+                 FROM (
+                     WITH cte AS (SELECT 1 AS id, 'left' AS payload)
